SELECT stable_name, phone_number, contact_email
FROM stables
WHERE location = 'Location B';

SELECT stable_id, stable_name
FROM stables
WHERE capacity >= (SELECT AVG(capacity) FROM stables);

SELECT DISTINCT horse_name 
FROM horses 
WHERE health_status <> 'Good';

SELECT horse_name, stable_id
FROM horses
WHERE horse_id = (SELECT MAX(horse_id) FROM horses);

SELECT rd.rider_driver_name, h.horse_name
FROM riders_drivers rd
INNER JOIN horses h ON rd.horse_id = h.horse_id;

SELECT horses.horse_name, riders_drivers.rider_driver_name
FROM horses
INNER JOIN riders_drivers ON horses.horse_id = riders_drivers.horse_id;

SELECT horse_name
FROM horses
WHERE exhibitor_id = 0 AND training_level != '';
